import numpy as np

# Define a function to compute complex math with memoization to cache computations
def complex_math(val):
    cache = {}
    if val not in cache:
        if val == 0:
            result = 1  # Assuming 1 as the result when val is 0
        else:
            result = (val ** 2 + (val / 2.5)) / (val + 1)
        cache[val] = result
    return cache[val]

def optimized_data_processor(data_list):
